#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAX 1000000

int main() {
    int Q;
    scanf("%d", &Q);
    char s[MAX + 1] = {0};
    int len = 0;
    long long sum = 0;
    for (int i = 0; i < Q; i++) {
        char op[2];
        scanf(" %c", op);
        if (op[0] == '+') {
            char c;
            scanf(" %c", &c);
            s[len++] = c;
            s[len] = '\0';
            long long count = 0;
            for (int j = 0; j < len; j++) {
                for (int k = j + 1; k <= len; k++) {
                    count++;
                }
            }
            sum = (sum + count) % MOD;
        } else {
            len--;
            s[len] = '\0';
            long long count = 0;
            for (int j = 0; j < len; j++) {
                for (int k = j + 1; k <= len; k++) {
                    count++;
                }
            }
            sum = (sum + count) % MOD;
        }
    }
    printf("%lld\n", sum);
    return 0;
}

